- "adventurers" refers to game characters;
- "roles in the tales" refers to the roles of the characters in the games;
- "epic sagas" refers to the titles of the video games.

sql:
SELECT COUNT(*) 
FROM game_titles 
WHERE release_date > 2008 AND genre = 'Action';

SELECT game_title
FROM game_titles
WHERE game_id = 0;

SELECT DISTINCT game_title
FROM game_titles
ORDER BY game_title ASC;

SELECT game_title, release_date
FROM game_titles
ORDER BY release_date ASC;

SELECT role 
FROM character_game_titles 
WHERE character_id = 1 AND game_id = 1;

SELECT COUNT(*)
FROM game_developers
WHERE last_activity >= '2023-01-01';

SELECT COUNT(*) AS recent_game_count
FROM game_titles
WHERE release_date > 2000;

SELECT firearm_name 
FROM firearms 
WHERE firearm_id = 1;
